SELECT id, tenant_id, username, password_hash, display_name, email, role, status,
       login_fail_count, locked_until, last_login_at, last_login_ip, password_updated_at,
       created_at, updated_at
FROM users
WHERE tenant_id = #{tenantId}

    AND username LIKE '%' || #{username} || '%'


    AND role = #{role}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM users
WHERE tenant_id = #{tenantId}

    AND username LIKE '%' || #{username} || '%'


    AND role = #{role}

SELECT COUNT(*)
FROM users
WHERE tenant_id = #{tenantId}
